import{_ as a}from"./chunks/placeholder.DuiHaLuQ.js";import{_ as i,o,c as r,ag as e,j as l,a as n}from"./chunks/framework.DXGyWiRo.js";const s="/media/202407/2024-07-30_112638_9061130.7688732084367446.png",p="/media/202409/2024-09-13_104057_1695630.5219667202223248.png",c="/media/202407/2024-07-30_113521_4592130.8746946376165508.png",k=JSON.parse('{"title":"意图配置","description":"","frontmatter":{"title":"意图配置"},"headers":[],"relativePath":"custom-biz/skill-studio/development/intent-config.md","filePath":"custom-biz/skill-studio/development/intent-config.md","lastUpdated":null}'),d={name:"custom-biz/skill-studio/development/intent-config.md"};function h(u,t,m,_,g,b){return o(),r("div",null,[...t[0]||(t[0]=[e('<p><strong>目录</strong></p><ol><li>语料设计 1.1. 语料说明 1.2. 压缩语料</li><li>编写句式选择 2.1. 智能贴弧开关选择 2.2. 定义语义槽 2.3. 定义辅助词</li><li>语义槽绑定实体 3.1. 自定义实体</li><li>填槽对话</li><li>技能回复</li><li>意图确认</li></ol><p><strong>意图配置</strong>主要就是语料填充编写，关于语料编写详细流程如下：</p><h2 id="语料设计" tabindex="-1">语料设计 <a class="header-anchor" href="#语料设计" aria-label="Permalink to &quot;语料设计&quot;">​</a></h2><h3 id="_1-1-语料说明" tabindex="-1">1.1. 语料说明 <a class="header-anchor" href="#_1-1-语料说明" aria-label="Permalink to &quot;1.1. 语料说明&quot;">​</a></h3><p>一个意图有多种说法，称为语料：</p><ul><li>查快递单号8888</li><li>顺丰单号8888到哪里了</li><li>……</li></ul><h3 id="_1-2-压缩语料" tabindex="-1">1.2. 压缩语料 <a class="header-anchor" href="#_1-2-压缩语料" aria-label="Permalink to &quot;1.2. 压缩语料&quot;">​</a></h3><p>对梳理的技能对话语料进行合并和压缩，具体方法可以有：</p><ul><li>使用模糊匹配方式，对关键信息进行处理。详见<a href="/custom-biz/skill-studio/fuzzy-match.html">模糊匹配</a>说明；</li><li>设置非关键信息为非必选字段或槽位，使用方式见<a href="/custom-biz/skill-studio/intents.html">可选符</a>说明，进行类似句式合并。</li></ul><p>我们将这些提问方式添加进入控制台，示例如下：</p><p><img src="'+a+'" alt="待补充：添加语料示例截图"></p><h2 id="编写句式选择" tabindex="-1">编写句式选择 <a class="header-anchor" href="#编写句式选择" aria-label="Permalink to &quot;编写句式选择&quot;">​</a></h2><p>在进行语料编辑时，可以选择的句式可以分两类，分别为：</p><ul><li><strong>例句语料</strong>： 纯文本句式，不使用标签符号进行槽位说明。需要进行槽位控制时，鼠标滑动选字符进行设置</li><li><strong>模板语料</strong>： 使用标签符号进行槽位说明，支持的符号详见<a href="/custom-biz/skill-studio/intents.html">意图和语料</a>说明；</li></ul><p>示例说明如下：</p><p><img src="'+s+'" alt="" title="null"></p><h3 id="_2-1-智能贴弧开关选择" tabindex="-1">2.1. 智能贴弧开关选择 <a class="header-anchor" href="#_2-1-智能贴弧开关选择" aria-label="Permalink to &quot;2.1. 智能贴弧开关选择&quot;">​</a></h3><p>系统自动判断<strong>例句语料</strong>的槽位，并匹配实体。当不需要系统进行智能槽位判断时，可进行手动关闭：</p><p><img src="'+p+'" alt="" title="null"></p><h3 id="_2-2-定义语义槽" tabindex="-1">2.2. 定义语义槽 <a class="header-anchor" href="#_2-2-定义语义槽" aria-label="Permalink to &quot;2.2. 定义语义槽&quot;">​</a></h3><p>用户说法:<code>查顺丰快递、查EMS、查圆通快递</code> 抽象语义槽并命名为company：<code>查{company}</code></p><h3 id="_2-3-定义辅助词" tabindex="-1">2.3. 定义辅助词 <a class="header-anchor" href="#_2-3-定义辅助词" aria-label="Permalink to &quot;2.3. 定义辅助词&quot;">​</a></h3><p><strong>辅助词</strong>：不改变句式含义的词，如我要、查询、帮我。</p><h2 id="语义槽绑定实体" tabindex="-1">语义槽绑定实体 <a class="header-anchor" href="#语义槽绑定实体" aria-label="Permalink to &quot;语义槽绑定实体&quot;">​</a></h2>',25),l("p",null,[n("将快递公司名总结为 "),l("strong",{expressCompany:""},"实体")],-1),e('<p>每个语义槽均需与实体绑定。在以上的例子中，我们将语义槽<code>{company}</code>与实体<code>expressCompany</code>绑定。</p><p><img src="'+a+'" alt="待补充：修改语义槽截图"></p><h3 id="_3-1-自定义实体" tabindex="-1">3.1. 自定义实体 <a class="header-anchor" href="#_3-1-自定义实体" aria-label="Permalink to &quot;3.1. 自定义实体&quot;">​</a></h3><p>讯飞有一些开放的实体可以供开发者调用，比如针对快递单号语义槽 {number} ，使用官方开放实体 <code>IFLYTEK.number</code> 可以很好的解决。 当官方实体不满足自由业务实体内容选择时，可以进行自定义实体来填充自己的数据。 以快递公司的名称为例，需要开发者自己总结。新建实体示例如下（具体用户该创建何种实体可以见<a href="/custom-biz/skill-studio/entities.html" title="实体文档">实体文档</a>说明自行选择）：</p><ul><li>实体类型：<code>静态实体</code></li><li>实体名称：<code>快递公司</code></li><li>实体标识：<code>expressCompany</code></li></ul><p><img src="'+a+'" alt="待补充：创建实体截图"></p><p>如下图为实体添加词条，建议<code>词条</code>填写归一化的实体名，<code>别名</code>填词条用户所有的可能表述方式。</p><p><img src="'+c+'" alt="" title="null"></p><h2 id="填槽对话" tabindex="-1">填槽对话 <a class="header-anchor" href="#填槽对话" aria-label="Permalink to &quot;填槽对话&quot;">​</a></h2><p>填槽对话用于追问用户补充缺失信息。可设置语义槽是否必填。</p><p>举例</p><ul><li>用户 ：查顺丰快递</li><li>讯飞 ：请告诉我快递单号 （填槽对话：追问单号信息）</li><li>用户 ：123</li></ul><p>若勾选对话必须，则可以且必须自定义追问语句（ElicitSlot）以及回答语料，否则技能可能无法命中。</p><p>开发者可以在「意图编辑页-实体」中将实体勾选为「对话必须」，当缺少必须的实体时，会主动追问，参照下图设置。</p><p><img src="'+a+'" alt="待补充：填槽配置截图"></p><p>平台暂不支持可视化的配置槽位确认（ConfirmSlot）</p><ul><li>关闭云函数时，系统会按照你在页面上的配置，依次引导用户填写<strong>必选槽位</strong></li><li>开启云函数时，你应当每次请求到来时，你都应当根据你的业务逻辑，判断此时此刻是否需要进行槽追问，槽确认，意图确认。如果你不想处理，可以使用 DelegateDirective（托管）指令，此时系统会根据当前的槽位状态以及你在平台上的配置，自动的去触发<strong>槽追问（ElicitSlot</strong>） 或者<strong>意图确认（ConfirmIntent）</strong>。</li></ul><p>填槽对话是意图内的多轮对话，详细概念可参考<a href="/custom-biz/skill-studio/slot-filling.html">填槽对话</a>章节。</p><h2 id="技能回复" tabindex="-1">技能回复 <a class="header-anchor" href="#技能回复" aria-label="Permalink to &quot;技能回复&quot;">​</a></h2><p>可按需添加，如不添加，“模拟测试”和端侧测试可能无法命中技能。</p><h2 id="意图确认" tabindex="-1">意图确认 <a class="header-anchor" href="#意图确认" aria-label="Permalink to &quot;意图确认&quot;">​</a></h2><blockquote><p>前提：勾选对话必须</p></blockquote><p>你可以选择开启意图确认（ConfirmIntent）并填写意图确认语句。</p>',23)])])}const x=i(d,[["render",h]]);export{k as __pageData,x as default};
